"use client";

import { motion, useMotionValue } from "motion/react";
import { Underdog } from "next/font/google";
import { useState } from "react";

export default function Linear() {
  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const z = useMotionValue(0);

  return (
    <>
      <div className="fixed z-500 top-5  right-5">
        <div className="flex">
            <h1 className="text-white">X</h1>
          <input
            type="range"
            min={0}
            max={360}
            value={undefined}
            onChange={(e) => x.set(Number(e.target.value))}
          />
          <h1 className="text-white">{Number(x)}</h1>
        </div>
        <div className="flex">
            <h1 className="text-white">Y</h1>
        <input
          type="range"
          min={0}
          max={360}
          value={undefined}
          onChange={(e) => y.set(Number(e.target.value))}
        />
            <h1 className="text-white">{Number(y)}</h1>
        </div>
        <div className="flex">
            <h1 className="text-white">Z</h1>
        <input
          type="range"
          min={0}
          max={360}
          value={undefined}
          onChange={(e) => z.set(Number(e.target.value))}
        />
            <h1 className="text-white">{Number(z)}</h1>
        </div>
      </div>

      <div className="h-screen w-screen flex justify-center items-center">
        <div
          className="fixed"
          style={{ perspective: "1000px", transformStyle: "preserve-3d" }}
        >
          {Array.from({ length: 100 }).map((_, i) => {
            return
            <motion.div
              key={i}
              className="h-40 w-32 border border-white rounded-xl bg-black fixed gap-z-3"
              style={{
                zIndex: i,
                transform: `translateZ(${(i*50)-5000}px) rotateX(${x}deg) rotateY(${y}deg) rotateZ(${z}deg)`,
              }}
            ></motion.div>
          })}
        </div>
      </div>
    </>
  );
}
